import java.time.Instant;

@Entity
@Table(name = "roles")
@Getter
@Setter
@NoArgsConstructor
public class Role {

    public enum RoleName {
        REGULAR_USER,
        WAREHOUSE_STAFF,
        ADMINISTRATOR
