package com.campusfit.auth.entity;

import com.campusfit.users.entity.User;
import jakarta.persistence.*;
import lombok.Getter;
import lombok.NoArgsConstructor;
import lombok.Setter;

import java.time.Instant;

@Entity
@Table(name = "sessions")
@Getter
@Setter
@NoArgsConstructor
public class Session {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(name = "token_hash", nullable = false, unique = true)
    private String tokenHash;

    @ManyToOne(fetch = FetchType.EAGER)
    @JoinColumn(name = "user_id", nullable = false)
    private User user;

    @Column(name = "created_at", nullable = false, updatable = false)
    private Instant createdAt;

    @Column(name = "last_seen_at")
    private Instant lastSeenAt;

    @Column(name = "idle_expires_at", nullable = false)
    private Instant idleExpiresAt;

    @Column(name = "absolute_expires_at", nullable = false)
    private Instant absoluteExpiresAt;

    @Column(name = "revoked_at")
    private Instant revokedAt;

    @Column(name = "user_agent", length = 500)
    private String userAgent;

    @Column(name = "ip_address", length = 45)
    private String ipAddress;

    @PrePersist
    protected void onCreate() {
        createdAt = Instant.now();
        lastSeenAt = Instant.now();
    }

    public boolean isExpired() {
        Instant now = Instant.now();
        return now.isAfter(idleExpiresAt) || now.isAfter(absoluteExpiresAt);
    }

    public boolean isRevoked() {
        return revokedAt != null;
    }

    public boolean isValid() {
        return !isExpired() && !isRevoked();
    }

    public void refreshIdleTimeout(int idleTimeoutMinutes) {
        Instant newIdleExpiry = Instant.now().plusSeconds(idleTimeoutMinutes * 60L);
        // Never extend beyond absolute lifetime
        if (newIdleExpiry.isAfter(absoluteExpiresAt)) {
            this.idleExpiresAt = absoluteExpiresAt;
        } else {
            this.idleExpiresAt = newIdleExpiry;
        }
        this.lastSeenAt = Instant.now();
    }
}

