    private final AppConfig appConfig;
    private final BCryptPasswordEncoder passwordEncoder;

    private static final SecureRandom SECURE_RANDOM = new SecureRandom();

    @Transactional
    public AuthResponse register(RegisterRequest request) {
        if (userRepository.existsByUsername(request.getUsername())) {
            throw new AppException("AUTH_USERNAME_EXISTS", "Username already taken", 409, null);
        }

        Role userRole = roleRepository.findByName(Role.RoleName.REGULAR_USER)
                .orElseThrow(() -> new AppException("ROLE_NOT_FOUND", "Default role not found", 500, null));

        User user = new User();
        user.setUsername(request.getUsername());
        user.setPasswordHash(passwordEncoder.encode(request.getPassword()));
        user.setEmail(request.getEmail());
        user.setFullName(request.getFullName());
        user.setRole(userRole);
        user.setStatus(User.UserStatus.ACTIVE);
        user = userRepository.save(user);

        auditService.log(user.getId(), "USER_REGISTERED", "USER", user.getId(), null);
        log.info("category=auth action=register userId={}", user.getId());

        return createSession(user, null, null);
    }

    @Transactional
    public AuthResponse login(LoginRequest request, String userAgent, String ipAddress) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new AppException("AUTH_INVALID_CREDENTIALS",
                        "Invalid username or password", 401, null));

        // Check lockout
        if (user.isLocked()) {
            log.warn("category=auth action=login_locked userId={}", user.getId());
            throw new AppException("AUTH_ACCOUNT_LOCKED",
                    "Account is locked. Try again later.", 423, null);
        }

        // Check suspension
        if (user.isSuspended()) {
            log.warn("category=auth action=login_suspended userId={}", user.getId());
            throw new AppException("AUTH_ACCOUNT_SUSPENDED",
                    "Account is suspended.", 403, null);
        }

        // Verify password
        if (!passwordEncoder.matches(request.getPassword(), user.getPasswordHash())) {
            handleFailedLogin(user);
            throw new AppException("AUTH_INVALID_CREDENTIALS",
                    "Invalid username or password", 401, null);
        }

        // Reset failed attempts on success
        user.setFailedLoginAttempts(0);
        user.setLockedUntil(null);
        user.setLastLoginAt(Instant.now());
        if (user.getStatus() == User.UserStatus.LOCKED) {
            user.setStatus(User.UserStatus.ACTIVE);
        }
        userRepository.save(user);

        auditService.log(user.getId(), "USER_LOGIN", "SESSION", null,
                Map.of("ip", ipAddress != null ? ipAddress : "unknown"));
        log.info("category=auth action=login userId={}", user.getId());

        return createSession(user, userAgent, ipAddress);
    }

    @Transactional
    public void logout(String tokenHash) {
        Session session = sessionRepository.findByTokenHash(tokenHash)
                .orElseThrow(() -> new AppException("SESSION_NOT_FOUND", "Session not found", 404, null));

        session.setRevokedAt(Instant.now());
        sessionRepository.save(session);

        auditService.log(session.getUser().getId(), "USER_LOGOUT", "SESSION", session.getId(), null);
        log.info("category=auth action=logout userId={}", session.getUser().getId());
    }

    @Transactional(readOnly = true)
    public Session validateSession(String token) {
        String tokenHash = hashToken(token);
        Session session = sessionRepository.findByTokenHash(tokenHash)
                .orElseThrow(() -> new AppException("AUTH_INVALID_SESSION",
                        "Invalid or expired session", 401, null));

        if (!session.isValid()) {
            throw new AppException("AUTH_SESSION_EXPIRED", "Session expired", 401, null);
        }

        // Check if user is still active
        User user = session.getUser();
        if (!user.isActive()) {
            throw new AppException("AUTH_ACCOUNT_INACTIVE", "Account is not active", 403, null);
        }

        return session;
    }

    @Transactional
    public void refreshSession(Session session) {
        session.refreshIdleTimeout(appConfig.getSecurity().getSessionIdleTimeoutMinutes());
        sessionRepository.save(session);
    }

    @Transactional
    public void revokeAllSessions(Long userId) {
        sessionRepository.revokeAllByUserId(userId, Instant.now());
        auditService.log(userId, "SESSIONS_REVOKED_ALL", "USER", userId, null);
    }

    public UserProfileResponse getCurrentUserProfile(User user) {
        return UserProfileResponse.builder()
                .id(user.getId())
                .username(user.getUsername())
                .email(user.getEmail())
                .fullName(user.getFullName())
                .role(user.getRole().getName().name())
                .status(user.getStatus().name())
                .lastLoginAt(user.getLastLoginAt() != null ? user.getLastLoginAt().toString() : null)
                .createdAt(user.getCreatedAt().toString())
                .build();
    }

    // --- Private helpers ---

    private void handleFailedLogin(User user) {
        int attempts = user.getFailedLoginAttempts() + 1;
        user.setFailedLoginAttempts(attempts);

        if (attempts >= appConfig.getSecurity().getLockoutThreshold()) {
            user.setLockedUntil(Instant.now().plus(
                    appConfig.getSecurity().getLockoutDurationMinutes(), ChronoUnit.MINUTES));
            user.setStatus(User.UserStatus.LOCKED);
            log.warn("category=auth action=account_locked userId={} attempts={}", user.getId(), attempts);
            auditService.log(user.getId(), "ACCOUNT_LOCKED", "USER", user.getId(),
                    Map.of("attempts", attempts));
        }

        userRepository.save(user);
        log.warn("category=auth action=login_failed userId={} attempts={}", user.getId(), attempts);
    }

    private AuthResponse createSession(User user, String userAgent, String ipAddress) {
        String rawToken = generateToken();
        String tokenHash = hashToken(rawToken);

        Instant now = Instant.now();
        int idleMinutes = appConfig.getSecurity().getSessionIdleTimeoutMinutes();
        int maxDays = appConfig.getSecurity().getSessionMaxLifetimeDays();

        Session session = new Session();
        session.setTokenHash(tokenHash);
        session.setUser(user);
        session.setIdleExpiresAt(now.plus(idleMinutes, ChronoUnit.MINUTES));
        session.setAbsoluteExpiresAt(now.plus(maxDays, ChronoUnit.DAYS));
        session.setUserAgent(userAgent);
        session.setIpAddress(ipAddress);
        sessionRepository.save(session);

        return AuthResponse.builder()
                .token(rawToken)
                .username(user.getUsername())
                .fullName(user.getFullName())
                .role(user.getRole().getName().name())
                .expiresAt(session.getAbsoluteExpiresAt().toEpochMilli())
                .build();
    }

    private String generateToken() {
        byte[] tokenBytes = new byte[32];
        SECURE_RANDOM.nextBytes(tokenBytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(tokenBytes);
    }

    static String hashToken(String token) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(token.getBytes(StandardCharsets.UTF_8));
            StringBuilder hex = new StringBuilder();
            for (byte b : hash) {
                hex.append(String.format("%02x", b));
            }
            return hex.toString();
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("SHA-256 not available", e);
        }
    }
}

