package com.campusfit.security;

import com.campusfit.config.AppConfig;
import lombok.RequiredArgsConstructor;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;

@Configuration
@EnableWebSecurity
@EnableMethodSecurity
@RequiredArgsConstructor
public class SecurityConfig {

    private final AppConfig appConfig;
    private final SessionAuthenticationFilter sessionAuthenticationFilter;

    @Bean
    public BCryptPasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder(appConfig.getSecurity().getBcryptCost());
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .csrf(AbstractHttpConfigurer::disable)
            .sessionManagement(sm -> sm.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
            .authorizeHttpRequests(auth -> auth
                // Public endpoints
                .requestMatchers("/api/v1/auth/login", "/api/v1/auth/register").permitAll()
                .requestMatchers("/health/live", "/health/ready").permitAll()
                // Static frontend files
                .requestMatchers("/", "/index.html", "/assets/**", "/favicon.ico").permitAll()
                // Admin-only endpoints
                .requestMatchers("/api/v1/admin/**").hasAuthority("ADMINISTRATOR")
                // Warehouse staff endpoints
                .requestMatchers("/api/v1/inventory/**").hasAnyAuthority("WAREHOUSE_STAFF", "ADMINISTRATOR")
                // Master data management — admin only
                .requestMatchers("/api/v1/masterdata/import/**", "/api/v1/masterdata/export/**",
                                 "/api/v1/masterdata/merge/**").hasAuthority("ADMINISTRATOR")
                .requestMatchers("/api/v1/masterdata/**").hasAnyAuthority("ADMINISTRATOR", "REGULAR_USER")
                // All other API endpoints require authentication
                .requestMatchers("/api/v1/**").authenticated()
                .anyRequest().permitAll()
            )
            .addFilterBefore(sessionAuthenticationFilter, UsernamePasswordAuthenticationFilter.class);

        return http.build();
    }
}

