package com.campusfit.security;

import com.campusfit.auth.entity.Session;
import com.campusfit.auth.service.AuthService;
import com.campusfit.common.exception.AppException;
import com.campusfit.users.entity.User;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.slf4j.MDC;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;
import java.util.List;

@Component
@RequiredArgsConstructor
@Slf4j
public class SessionAuthenticationFilter extends OncePerRequestFilter {

    private final AuthService authService;

    private static final String AUTH_HEADER = "Authorization";
    private static final String BEARER_PREFIX = "Bearer ";

    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                     HttpServletResponse response,
                                     FilterChain filterChain) throws ServletException, IOException {
        String authHeader = request.getHeader(AUTH_HEADER);

        if (authHeader != null && authHeader.startsWith(BEARER_PREFIX)) {
            String token = authHeader.substring(BEARER_PREFIX.length());

            try {
                Session session = authService.validateSession(token);
                User user = session.getUser();

                // Refresh idle timeout
                authService.refreshSession(session);

                // Set MDC for structured logging
                MDC.put("actorId", String.valueOf(user.getId()));

                // Set Spring Security context
                String roleName = user.getRole().getName().name();
                UsernamePasswordAuthenticationToken auth =
                        new UsernamePasswordAuthenticationToken(
                                user, null,
                                List.of(new SimpleGrantedAuthority(roleName))
                        );
                SecurityContextHolder.getContext().setAuthentication(auth);

            } catch (AppException e) {
                // Don't set auth — the request proceeds as unauthenticated
                log.debug("category=auth action=session_validation_failed reason={}", e.getCode());
            }
        }

        try {
            filterChain.doFilter(request, response);
        } finally {
            MDC.remove("actorId");
        }
    }

    @Override
    protected boolean shouldNotFilter(HttpServletRequest request) {
        String path = request.getRequestURI();
        return path.equals("/api/v1/auth/login") ||
               path.equals("/api/v1/auth/register") ||
               path.startsWith("/health/") ||
               path.equals("/") ||
               path.equals("/index.html") ||
               path.startsWith("/assets/") ||
               path.equals("/favicon.ico");
    }
}

