 * Utility for accessing the current authenticated user from the security context.
 * Used throughout services for object-level authorization.
 */
public final class AuthContext {

    private AuthContext() {}

    public static User getCurrentUser() {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth == null || !(auth.getPrincipal() instanceof User)) {
            throw new AppException("AUTH_REQUIRED", "Authentication required", 401, null);
        }
        return (User) auth.getPrincipal();
    }

    public static Long getCurrentUserId() {
        return getCurrentUser().getId();
    }

    public static Role.RoleName getCurrentRole() {
        return getCurrentUser().getRole().getName();
    }

    public static boolean isAdmin() {
        return getCurrentRole() == Role.RoleName.ADMINISTRATOR;
    }

    public static boolean isWarehouseStaff() {
        return getCurrentRole() == Role.RoleName.WAREHOUSE_STAFF;
    }

    public static boolean isRegularUser() {
        return getCurrentRole() == Role.RoleName.REGULAR_USER;
    }

    /**
     * Enforce that the current user owns the given resource.
     * Used for object-level authorization.
     */
    public static void requireOwner(Long resourceOwnerId) {
        if (!getCurrentUserId().equals(resourceOwnerId) && !isAdmin()) {
            throw new AppException("AUTH_FORBIDDEN", "Access denied", 403, null);
        }
    }

    /**
     * Enforce a specific role.
     */
    public static void requireRole(Role.RoleName... roles) {
        Role.RoleName current = getCurrentRole();
        for (Role.RoleName role : roles) {
            if (current == role) return;
        }
        throw new AppException("AUTH_FORBIDDEN", "Insufficient permissions", 403, null);
    }
}

