package com.campusfit.health.controller;

import com.campusfit.config.AppConfig;
import com.campusfit.security.AuthContext;
import lombok.RequiredArgsConstructor;
import org.springframework.http.ResponseEntity;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.io.File;
import java.time.Instant;
import java.util.LinkedHashMap;
import java.util.Map;

@RestController
@RequestMapping("/health")
@RequiredArgsConstructor
public class HealthController {

    private final JdbcTemplate jdbcTemplate;
    private final AppConfig appConfig;

    /**
     * Minimal liveness probe — always returns 200 if the JVM is running.
     */
    @GetMapping("/live")
    public ResponseEntity<Map<String, String>> live() {
        return ResponseEntity.ok(Map.of("status", "UP", "timestamp", Instant.now().toString()));
    }

    /**
     * Detailed readiness check — checks DB, storage, key directory.
     * Accessible by all authenticated users for basic info; admin sees full details.
     */
    @GetMapping("/ready")
    public ResponseEntity<Map<String, Object>> ready() {
        Map<String, Object> health = new LinkedHashMap<>();
        health.put("status", "UP");
        health.put("timestamp", Instant.now().toString());

        // DB connectivity
        try {
            jdbcTemplate.queryForObject("SELECT 1", Integer.class);
            health.put("database", Map.of("status", "UP"));
        } catch (Exception e) {
            health.put("database", Map.of("status", "DOWN", "error", "Connection failed"));
            health.put("status", "DEGRADED");
        }

        // Storage directory
        File storageDir = new File(appConfig.getStorage().getRoot());
        health.put("storage", Map.of(
                "status", storageDir.exists() && storageDir.canWrite() ? "UP" : "DOWN",
                "path", appConfig.getStorage().getRoot()
        ));

        // Backup directory
        File backupDir = new File(appConfig.getStorage().getBackupRoot());
        health.put("backups", Map.of(
                "status", backupDir.exists() && backupDir.canWrite() ? "UP" : "DOWN",
                "path", appConfig.getStorage().getBackupRoot()
        ));

        // Key directory
        File keyDir = new File(appConfig.getEncryption().getKeyDir());
        health.put("encryption", Map.of(
                "status", keyDir.exists() && keyDir.canRead() ? "UP" : "DOWN",
                "activeKeyId", appConfig.getEncryption().getActiveKeyId()
        ));

        return ResponseEntity.ok(health);
    }
}

