import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import { authApi } from '../api/auth'

export const useAuthStore = defineStore('auth', () => {
  const token = ref(localStorage.getItem('campusfit_token') || null)
  const user = ref(JSON.parse(localStorage.getItem('campusfit_user') || 'null'))

  const isAuthenticated = computed(() => !!token.value)
  const userRole = computed(() => user.value?.role || null)
  const isAdmin = computed(() => userRole.value === 'ADMINISTRATOR')
  const isWarehouseStaff = computed(() => userRole.value === 'WAREHOUSE_STAFF')
  const isRegularUser = computed(() => userRole.value === 'REGULAR_USER')

  async function login(username, password) {
    const { data } = await authApi.login(username, password)
    token.value = data.token
    user.value = { username: data.username, fullName: data.fullName, role: data.role }
    localStorage.setItem('campusfit_token', data.token)
    localStorage.setItem('campusfit_user', JSON.stringify(user.value))
    return data
  }

  async function register(formData) {
    const { data } = await authApi.register(formData)
    token.value = data.token
    user.value = { username: data.username, fullName: data.fullName, role: data.role }
    localStorage.setItem('campusfit_token', data.token)
    localStorage.setItem('campusfit_user', JSON.stringify(user.value))
    return data
  }

  async function logout() {
    try {
      await authApi.logout()
    } finally {
      token.value = null
      user.value = null
      localStorage.removeItem('campusfit_token')
      localStorage.removeItem('campusfit_user')
    }
  }

  async function fetchProfile() {
    const { data } = await authApi.getProfile()
    user.value = data
    localStorage.setItem('campusfit_user', JSON.stringify(data))
    return data
  }

  return { token, user, isAuthenticated, userRole, isAdmin, isWarehouseStaff, isRegularUser, login, register, logout, fetchProfile }
})

