import { defineStore } from 'pinia'
import { ref } from 'vue'
import { notificationsApi } from '../api/notifications'

export const useNotificationStore = defineStore('notifications', () => {
  const unreadCount = ref(0)
  const notifications = ref([])
  const loading = ref(false)

  async function fetchUnreadCount() {
    const { data } = await notificationsApi.getUnreadCount()
    unreadCount.value = data.count || 0
  }

  async function fetchNotifications(page = 0, size = 25) {
    loading.value = true
    try {
      const { data } = await notificationsApi.getNotifications(page, size)
      notifications.value = data.content || []
      return data
    } finally {
      loading.value = false
    }
  }

  async function markAsRead(id) {
    await notificationsApi.markAsRead(id)
    const n = notifications.value.find(n => n.id === id)
    if (n) n.readAt = new Date().toISOString()
    unreadCount.value = Math.max(0, unreadCount.value - 1)
  }

  async function markAllAsRead() {
    await notificationsApi.markAllAsRead()
    notifications.value.forEach(n => { if (!n.readAt) n.readAt = new Date().toISOString() })
    unreadCount.value = 0
  }

  return { unreadCount, notifications, loading, fetchUnreadCount, fetchNotifications, markAsRead, markAllAsRead }
})

