import { useAuthStore } from '../stores/auth'

const routes = [
  // Auth
  { path: '/login', name: 'Login', component: () => import('../views/auth/LoginView.vue'), meta: { guest: true } },
  { path: '/register', name: 'Register', component: () => import('../views/auth/RegisterView.vue'), meta: { guest: true } },

  // Dashboard
  { path: '/', name: 'Dashboard', component: () => import('../views/dashboard/DashboardView.vue'), meta: { auth: true } },

  // Fitness (Regular User)
  { path: '/fitness', name: 'Fitness', component: () => import('../views/fitness/FitnessView.vue'), meta: { auth: true, roles: ['REGULAR_USER', 'ADMINISTRATOR'] } },
  { path: '/fitness/assessment', name: 'FitnessAssessment', component: () => import('../views/fitness/AssessmentView.vue'), meta: { auth: true, roles: ['REGULAR_USER', 'ADMINISTRATOR'] } },
  { path: '/fitness/goals/new', name: 'NewGoal', component: () => import('../views/fitness/NewGoalView.vue'), meta: { auth: true, roles: ['REGULAR_USER', 'ADMINISTRATOR'] } },
  { path: '/fitness/goals/:id', name: 'GoalDetail', component: () => import('../views/fitness/GoalDetailView.vue'), meta: { auth: true, roles: ['REGULAR_USER', 'ADMINISTRATOR'] } },

  // Study (Regular User)
  { path: '/study', name: 'Study', component: () => import('../views/study/StudyView.vue'), meta: { auth: true, roles: ['REGULAR_USER', 'ADMINISTRATOR'] } },
  { path: '/study/plans/new', name: 'NewPlan', component: () => import('../views/study/NewPlanView.vue'), meta: { auth: true, roles: ['REGULAR_USER', 'ADMINISTRATOR'] } },
  { path: '/study/plans/:id', name: 'PlanDetail', component: () => import('../views/study/PlanDetailView.vue'), meta: { auth: true, roles: ['REGULAR_USER', 'ADMINISTRATOR'] } },

  // Inventory (Warehouse Staff / Admin)
  { path: '/inventory', name: 'Inventory', component: () => import('../views/inventory/InventoryView.vue'), meta: { auth: true, roles: ['WAREHOUSE_STAFF', 'ADMINISTRATOR'] } },
  { path: '/inventory/receipts/new', name: 'NewReceipt', component: () => import('../views/inventory/NewReceiptView.vue'), meta: { auth: true, roles: ['WAREHOUSE_STAFF', 'ADMINISTRATOR'] } },
  { path: '/inventory/receipts/:id', name: 'ReceiptDetail', component: () => import('../views/inventory/ReceiptDetailView.vue'), meta: { auth: true, roles: ['WAREHOUSE_STAFF', 'ADMINISTRATOR'] } },

  // Master Data (Admin)
  { path: '/masterdata', name: 'MasterData', component: () => import('../views/masterdata/MasterDataView.vue'), meta: { auth: true, roles: ['ADMINISTRATOR'] } },

  // Notifications
  { path: '/notifications', name: 'Notifications', component: () => import('../views/notifications/NotificationsView.vue'), meta: { auth: true } },

  // Admin
  { path: '/admin', name: 'Admin', component: () => import('../views/admin/AdminView.vue'), meta: { auth: true, roles: ['ADMINISTRATOR'] } },
  { path: '/admin/users', name: 'UserManagement', component: () => import('../views/admin/UserManagementView.vue'), meta: { auth: true, roles: ['ADMINISTRATOR'] } },
  { path: '/admin/audit', name: 'AuditLogs', component: () => import('../views/admin/AuditLogsView.vue'), meta: { auth: true, roles: ['ADMINISTRATOR'] } },
  { path: '/admin/performance', name: 'Performance', component: () => import('../views/admin/PerformanceView.vue'), meta: { auth: true, roles: ['ADMINISTRATOR'] } },
]

const router = createRouter({
  history: createWebHistory(),
  routes
})

router.beforeEach((to, from, next) => {
  const auth = useAuthStore()

  if (to.meta.auth && !auth.isAuthenticated) {
    return next('/login')
  }
  if (to.meta.guest && auth.isAuthenticated) {
    return next('/')
  }
  if (to.meta.roles && !to.meta.roles.includes(auth.userRole)) {
    return next('/')
  }
  next()
})

export default router

