package com.campusfit.auth.service;

import com.campusfit.auth.repository.SessionRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;
import org.springframework.transaction.annotation.Transactional;

import java.time.Instant;

/**
 * Scheduled job to clean up expired and revoked sessions.
 * Runs every 5 minutes to keep the sessions table manageable.
 */
@Component
@RequiredArgsConstructor
@Slf4j
public class SessionCleanupJob {

    private final SessionRepository sessionRepository;

    @Scheduled(fixedRate = 300_000) // every 5 minutes
    @Transactional
    public void cleanupExpiredSessions() {
        Instant cutoff = Instant.now();
        int deleted = sessionRepository.deleteExpiredSessions(cutoff);
        if (deleted > 0) {
            log.info("category=auth action=session_cleanup deleted={}", deleted);
        }
    }
}

