        req.setUsername(username);
        req.setPassword("Test1234!");
        req.setEmail(username + "@test.com");
        req.setFullName("Test User");
        return req;
    }

    private LoginRequest makeLoginRequest(String username, String password) {
        LoginRequest req = new LoginRequest();
        req.setUsername(username);
        req.setPassword(password);
        return req;
    }

    @Test
    void testRegisterSuccess() {
        AuthResponse resp = authService.register(makeRegisterRequest("newuser1"));
        assertNotNull(resp.getToken());
        assertEquals("newuser1", resp.getUsername());
        assertEquals("REGULAR_USER", resp.getRole());
        assertTrue(userRepository.existsByUsername("newuser1"));
    }

    @Test
    void testRegisterDuplicateUsername() {
        authService.register(makeRegisterRequest("dupuser"));
        AppException ex = assertThrows(AppException.class,
                () -> authService.register(makeRegisterRequest("dupuser")));
        assertEquals("AUTH_USERNAME_EXISTS", ex.getCode());
        assertEquals(409, ex.getHttpStatus());
    }

    @Test
    void testLoginSuccess() {
        authService.register(makeRegisterRequest("loginuser"));
