                makeLoginRequest("loginuser", "Test1234!"), "TestAgent", "127.0.0.1");
        assertNotNull(resp.getToken());
        assertEquals("loginuser", resp.getUsername());
    }

    @Test
    void testLoginInvalidPassword() {
        authService.register(makeRegisterRequest("badpw"));
