                () -> authService.login(makeLoginRequest("badpw", "WrongPass!"), null, null));
        assertEquals("AUTH_INVALID_CREDENTIALS", ex.getCode());
        assertEquals(401, ex.getHttpStatus());
    }

    @Test
    void testAccountLockoutAfterFiveFailures() {
        authService.register(makeRegisterRequest("lockme"));
        for (int i = 0; i < 5; i++) {
            assertThrows(AppException.class,
                    () -> authService.login(makeLoginRequest("lockme", "Wrong!"), null, null));
