        assertEquals("AUTH_ACCOUNT_LOCKED", ex.getCode());
    }

    @Test
    void testAccountLockoutExpires() {
        authService.register(makeRegisterRequest("lockexp"));
        for (int i = 0; i < 5; i++) {
            assertThrows(AppException.class,
                    () -> authService.login(makeLoginRequest("lockexp", "Wrong!"), null, null));
        }
        // Manually set lockedUntil to the past
        User user = userRepository.findByUsername("lockexp").orElseThrow();
        user.setLockedUntil(Instant.now().minus(1, ChronoUnit.HOURS));
        user.setStatus(User.UserStatus.ACTIVE);
        userRepository.save(user);

        AuthResponse resp = authService.login(
                makeLoginRequest("lockexp", "Test1234!"), null, null);
        assertNotNull(resp.getToken());
    }

    @Test
    void testSessionIdleExpiry() {
        AuthResponse resp = authService.register(makeRegisterRequest("idleuser"));
        String tokenHash = AuthService.hashToken(resp.getToken());
        Session session = sessionRepository.findByTokenHash(tokenHash).orElseThrow();
        session.setIdleExpiresAt(Instant.now().minus(1, ChronoUnit.HOURS));
        sessionRepository.save(session);

        AppException ex = assertThrows(AppException.class,
                () -> authService.validateSession(resp.getToken()));
        assertEquals("AUTH_SESSION_EXPIRED", ex.getCode());
    }

    @Test
    void testSessionAbsoluteExpiry() {
        AuthResponse resp = authService.register(makeRegisterRequest("absuser"));
        String tokenHash = AuthService.hashToken(resp.getToken());
        Session session = sessionRepository.findByTokenHash(tokenHash).orElseThrow();
        session.setAbsoluteExpiresAt(Instant.now().minus(1, ChronoUnit.HOURS));
        session.setIdleExpiresAt(Instant.now().minus(1, ChronoUnit.HOURS));
        sessionRepository.save(session);

        AppException ex = assertThrows(AppException.class,
                () -> authService.validateSession(resp.getToken()));
        assertEquals("AUTH_SESSION_EXPIRED", ex.getCode());
    }

    @Test
    void testSessionRefreshNeverExceedsAbsolute() {
        AuthResponse resp = authService.register(makeRegisterRequest("refuser"));
        String tokenHash = AuthService.hashToken(resp.getToken());
        Session session = sessionRepository.findByTokenHash(tokenHash).orElseThrow();
        // Set absolute to 5 minutes from now
        Instant absoluteExpiry = Instant.now().plus(5, ChronoUnit.MINUTES);
        session.setAbsoluteExpiresAt(absoluteExpiry);
        session.refreshIdleTimeout(appConfig.getSecurity().getSessionIdleTimeoutMinutes());

        assertTrue(session.getIdleExpiresAt().compareTo(absoluteExpiry) <= 0);
    }

    @Test
    void testLogoutRevokesSession() {
        AuthResponse resp = authService.register(makeRegisterRequest("logoutuser"));
        String tokenHash = AuthService.hashToken(resp.getToken());
        authService.logout(tokenHash);

        AppException ex = assertThrows(AppException.class,
                () -> authService.validateSession(resp.getToken()));
        assertTrue(ex.getCode().contains("SESSION") || ex.getCode().contains("AUTH"));
    }

    @Test
    void testPasswordHashingCost() {
        String raw = "TestPassword123!";
        String hash = passwordEncoder.encode(raw);
        assertTrue(passwordEncoder.matches(raw, hash));
        assertFalse(passwordEncoder.matches("WrongPassword", hash));
    }

    @Test
    void testSuspendedUserCannotLogin() {
        authService.register(makeRegisterRequest("suspended1"));
        User user = userRepository.findByUsername("suspended1").orElseThrow();
        user.setStatus(User.UserStatus.SUSPENDED);
        userRepository.save(user);

        AppException ex = assertThrows(AppException.class,
                () -> authService.login(makeLoginRequest("suspended1", "Test1234!"), null, null));
        assertEquals("AUTH_ACCOUNT_SUSPENDED", ex.getCode());
        assertEquals(403, ex.getHttpStatus());
    }
}

