package com.campusfit.auth;

import com.campusfit.auth.dto.LoginRequest;
import com.campusfit.auth.dto.RegisterRequest;
import com.campusfit.auth.dto.AuthResponse;
import com.campusfit.auth.entity.Role;
import com.campusfit.auth.entity.Session;
import com.campusfit.auth.repository.RoleRepository;
import com.campusfit.auth.repository.SessionRepository;
import com.campusfit.auth.service.AuthService;
import com.campusfit.common.exception.AppException;
import com.campusfit.users.entity.User;
import com.campusfit.users.repository.UserRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.transaction.annotation.Transactional;

import java.time.Instant;
import java.time.temporal.ChronoUnit;

import static org.junit.jupiter.api.Assertions.*;

@SpringBootTest
@ActiveProfiles("test")
@Transactional
class AuthServiceTest {

    @Autowired private AuthService authService;
    @Autowired private UserRepository userRepository;
    @Autowired private RoleRepository roleRepository;
    @Autowired private SessionRepository sessionRepository;
    @Autowired private BCryptPasswordEncoder passwordEncoder;

    @BeforeEach
    void setUp() {
        if (roleRepository.findByName(Role.RoleName.REGULAR_USER).isEmpty()) {
            roleRepository.save(new Role(Role.RoleName.REGULAR_USER));
            roleRepository.save(new Role(Role.RoleName.WAREHOUSE_STAFF));
            roleRepository.save(new Role(Role.RoleName.ADMINISTRATOR));
        }
    }

    @Test
    void testRegisterSuccess() {
        RegisterRequest req = new RegisterRequest();
        req.setUsername("testuser");
        req.setPassword("password123");
        req.setEmail("test@example.com");
        req.setFullName("Test User");

        AuthResponse response = authService.register(req);

        assertNotNull(response.getToken());
        assertEquals("testuser", response.getUsername());
        assertEquals("REGULAR_USER", response.getRole());
        assertTrue(userRepository.existsByUsername("testuser"));
    }

    @Test
    void testRegisterDuplicateUsername() {
        RegisterRequest req = new RegisterRequest();
        req.setUsername("duplicate");
        req.setPassword("password123");
        authService.register(req);

        RegisterRequest req2 = new RegisterRequest();
        req2.setUsername("duplicate");
        req2.setPassword("password456");

        AppException ex = assertThrows(AppException.class, () -> authService.register(req2));
        assertEquals(409, ex.getHttpStatus());
        assertEquals("AUTH_USERNAME_EXISTS", ex.getCode());
    }

    @Test
    void testLoginSuccess() {
        RegisterRequest reg = new RegisterRequest();
        reg.setUsername("loginuser");
        reg.setPassword("password123");
        authService.register(reg);

        LoginRequest login = new LoginRequest();
        login.setUsername("loginuser");
        login.setPassword("password123");

        AuthResponse response = authService.login(login, "TestAgent", "127.0.0.1");
        assertNotNull(response.getToken());
        assertEquals("loginuser", response.getUsername());
    }

    @Test
    void testLoginInvalidPassword() {
        RegisterRequest reg = new RegisterRequest();
        reg.setUsername("wrongpw");
        reg.setPassword("correctpass");
        authService.register(reg);

        LoginRequest login = new LoginRequest();
        login.setUsername("wrongpw");
        login.setPassword("wrongpass");

        AppException ex = assertThrows(AppException.class,
                () -> authService.login(login, null, "127.0.0.1"));
        assertEquals(401, ex.getHttpStatus());
    }

    @Test
    void testAccountLockoutAfterFiveFailures() {
        RegisterRequest reg = new RegisterRequest();
        reg.setUsername("lockme");
        reg.setPassword("correctpass");
        authService.register(reg);

        LoginRequest badLogin = new LoginRequest();
        badLogin.setUsername("lockme");
        badLogin.setPassword("wrongpass");

        for (int i = 0; i < 5; i++) {
            assertThrows(AppException.class,
                    () -> authService.login(badLogin, null, "127.0.0.1"));
        }

        // 6th attempt should be locked
        AppException ex = assertThrows(AppException.class,
                () -> authService.login(badLogin, null, "127.0.0.1"));
        assertEquals(423, ex.getHttpStatus());
        assertEquals("AUTH_ACCOUNT_LOCKED", ex.getCode());

        User user = userRepository.findByUsername("lockme").get();
        assertEquals(User.UserStatus.LOCKED, user.getStatus());
        assertNotNull(user.getLockedUntil());
    }

    @Test
    void testSessionIdleExpiry() {
        RegisterRequest reg = new RegisterRequest();
        reg.setUsername("expireuser");
        reg.setPassword("password123");
        AuthResponse response = authService.register(reg);

        // Manually expire the session
        String tokenHash = AuthService.hashToken(response.getToken());
        Session session = sessionRepository.findByTokenHash(tokenHash).get();
        session.setIdleExpiresAt(Instant.now().minus(1, ChronoUnit.HOURS));
        sessionRepository.save(session);

        AppException ex = assertThrows(AppException.class,
                () -> authService.validateSession(response.getToken()));
        assertEquals(401, ex.getHttpStatus());
    }

    @Test
    void testSessionAbsoluteExpiry() {
        RegisterRequest reg = new RegisterRequest();
        reg.setUsername("absexpire");
        reg.setPassword("password123");
        AuthResponse response = authService.register(reg);

        String tokenHash = AuthService.hashToken(response.getToken());
        Session session = sessionRepository.findByTokenHash(tokenHash).get();
        session.setAbsoluteExpiresAt(Instant.now().minus(1, ChronoUnit.DAYS));
        session.setIdleExpiresAt(Instant.now().minus(1, ChronoUnit.DAYS));
        sessionRepository.save(session);

        AppException ex = assertThrows(AppException.class,
                () -> authService.validateSession(response.getToken()));
        assertEquals(401, ex.getHttpStatus());
    }

    @Test
    void testSessionRefreshNeverExceedsAbsolute() {
        RegisterRequest reg = new RegisterRequest();
        reg.setUsername("refreshuser");
        reg.setPassword("password123");
        AuthResponse response = authService.register(reg);

        String tokenHash = AuthService.hashToken(response.getToken());
        Session session = sessionRepository.findByTokenHash(tokenHash).get();

        // Set absolute to 5 minutes from now
        session.setAbsoluteExpiresAt(Instant.now().plus(5, ChronoUnit.MINUTES));
        sessionRepository.save(session);

        // Refresh with 30-minute idle timeout
        session.refreshIdleTimeout(30);
        assertTrue(session.getIdleExpiresAt().compareTo(session.getAbsoluteExpiresAt()) <= 0);
    }

    @Test
    void testLogoutRevokesSession() {
        RegisterRequest reg = new RegisterRequest();
        reg.setUsername("logoutuser");
        reg.setPassword("password123");
        AuthResponse response = authService.register(reg);

        String tokenHash = AuthService.hashToken(response.getToken());
        authService.logout(tokenHash);

        Session session = sessionRepository.findByTokenHash(tokenHash).get();
        assertNotNull(session.getRevokedAt());
        assertFalse(session.isValid());
    }

    @Test
    void testPasswordHashingCost() {
        String raw = "testPassword123";
        String hash = passwordEncoder.encode(raw);
        assertTrue(passwordEncoder.matches(raw, hash));
        assertFalse(passwordEncoder.matches("wrongPassword", hash));
    }

    @Test
    void testSuspendedUserCannotLogin() {
        RegisterRequest reg = new RegisterRequest();
        reg.setUsername("suspended");
        reg.setPassword("password123");
        authService.register(reg);

        User user = userRepository.findByUsername("suspended").get();
        user.setStatus(User.UserStatus.SUSPENDED);
        userRepository.save(user);

        LoginRequest login = new LoginRequest();
        login.setUsername("suspended");
        login.setPassword("password123");

        AppException ex = assertThrows(AppException.class,
                () -> authService.login(login, null, "127.0.0.1"));
        assertEquals(403, ex.getHttpStatus());
        assertEquals("AUTH_ACCOUNT_SUSPENDED", ex.getCode());
    }
}

