import com.campusfit.common.util.DateUtils;
import org.junit.jupiter.api.Test;

import java.time.DayOfWeek;
import java.time.LocalDate;

import static org.junit.jupiter.api.Assertions.*;

class DateUtilsTest {

    @Test
    void testParseDate() {
        LocalDate date = DateUtils.parseDate("04/09/2026");
        assertEquals(2026, date.getYear());
        assertEquals(4, date.getMonthValue());
        assertEquals(9, date.getDayOfMonth());
    }

    @Test
    void testParseDateInvalid() {
        assertThrows(Exception.class, () -> DateUtils.parseDate("invalid"));
        assertThrows(Exception.class, () -> DateUtils.parseDate("2026-04-09"));
    }

    @Test
    void testIsBusinessDay() {
        // 04/06/2026 is a Monday
        LocalDate monday = LocalDate.of(2026, 4, 6);
        assertTrue(DateUtils.isBusinessDay(monday));

        LocalDate friday = LocalDate.of(2026, 4, 10);
        assertTrue(DateUtils.isBusinessDay(friday));

        LocalDate saturday = LocalDate.of(2026, 4, 11);
        assertFalse(DateUtils.isBusinessDay(saturday));

        LocalDate sunday = LocalDate.of(2026, 4, 12);
        assertFalse(DateUtils.isBusinessDay(sunday));
    }

    @Test
    void testAddBusinessDays() {
        // Friday + 1 business day = Monday
        LocalDate friday = LocalDate.of(2026, 4, 10);
        LocalDate result = DateUtils.addBusinessDays(friday, 1);
        assertEquals(DayOfWeek.MONDAY, result.getDayOfWeek());
        assertEquals(LocalDate.of(2026, 4, 13), result);
    }

    @Test
    void testAddBusinessDays5() {
        // Monday + 5 business days = Monday next week
        LocalDate monday = LocalDate.of(2026, 4, 6);
        LocalDate result = DateUtils.addBusinessDays(monday, 5);
        assertEquals(DayOfWeek.MONDAY, result.getDayOfWeek());
        assertEquals(LocalDate.of(2026, 4, 13), result);
    }

    @Test
    void testFormatDate() {
        LocalDate date = LocalDate.of(2026, 4, 9);
        assertEquals("04/09/2026", DateUtils.formatDate(date));
    }
}

