package com.campusfit.fitness;

import com.campusfit.auth.entity.Role;
import com.campusfit.auth.repository.RoleRepository;
import com.campusfit.common.exception.AppException;
import com.campusfit.fitness.dto.*;
import com.campusfit.fitness.entity.FitnessGoal;
import com.campusfit.fitness.entity.GoalPhase;
import com.campusfit.fitness.repository.FitnessGoalRepository;
import com.campusfit.fitness.repository.GoalPhaseRepository;
import com.campusfit.fitness.repository.WeeklyCheckinRepository;
import com.campusfit.fitness.service.FitnessService;
import com.campusfit.users.entity.User;
import com.campusfit.users.repository.UserRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.data.domain.PageRequest;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

@SpringBootTest
@ActiveProfiles("test")
@Transactional
class FitnessServiceTest {

    @Autowired private FitnessService fitnessService;
    @Autowired private UserRepository userRepository;
    @Autowired private RoleRepository roleRepository;
    @Autowired private FitnessGoalRepository goalRepository;
    @Autowired private GoalPhaseRepository phaseRepository;
    @Autowired private WeeklyCheckinRepository checkinRepository;
    @Autowired private BCryptPasswordEncoder passwordEncoder;

    private User testUser;
    private static final DateTimeFormatter FMT = DateTimeFormatter.ofPattern("MM/dd/yyyy");

    @BeforeEach
    void setUp() {
        if (roleRepository.findByName(Role.RoleName.REGULAR_USER).isEmpty()) {
            roleRepository.save(new Role(Role.RoleName.REGULAR_USER));
            roleRepository.save(new Role(Role.RoleName.WAREHOUSE_STAFF));
            roleRepository.save(new Role(Role.RoleName.ADMINISTRATOR));
        }
        Role role = roleRepository.findByName(Role.RoleName.REGULAR_USER).orElseThrow();
        testUser = new User();
        testUser.setUsername("fitnessuser_" + System.nanoTime());
        testUser.setPasswordHash(passwordEncoder.encode("Test1234!"));
        testUser.setRole(role);
        testUser.setStatus(User.UserStatus.ACTIVE);
        testUser = userRepository.save(testUser);
        setSecurityContext(testUser);
    }

    private void setSecurityContext(User user) {
        SecurityContextHolder.getContext().setAuthentication(
                new UsernamePasswordAuthenticationToken(user, null,
                        List.of(new SimpleGrantedAuthority(user.getRole().getName().name()))));
    }

    @Test
    void testCreateAssessment() {
        AssessmentRequest req = new AssessmentRequest();
        req.setHeightFt(5);
        req.setHeightIn(10);
        req.setWeightLb(new BigDecimal("180.50"));
        req.setAssessmentDate(LocalDate.now().format(FMT));
        AssessmentResponse resp = fitnessService.createAssessment(testUser.getId(), req);
        assertNotNull(resp);
        assertEquals(5, resp.getHeightFt());
        assertEquals(new BigDecimal("180.50"), resp.getWeightLb());
    }

    @Test
    void testCreateGoalWithPhases() {
        GoalRequest req = new GoalRequest();
        req.setGoalType("WEIGHT_LOSS");
        req.setTargetValue(new BigDecimal("12.00"));
        req.setTargetUnit("lb");
        req.setDurationWeeks(12);
        req.setStartDate(LocalDate.now().format(FMT));
        GoalResponse resp = fitnessService.createGoal(testUser.getId(), req);
        assertNotNull(resp);
        assertNotNull(resp.getPhases());
        assertTrue(resp.getPhases().size() >= 3 && resp.getPhases().size() <= 5,
                "Should create 3-5 phases, got " + resp.getPhases().size());
    }

    @Test
    void testPerformCheckin() {
        GoalRequest goalReq = new GoalRequest();
        goalReq.setGoalType("WEIGHT_LOSS");
        goalReq.setTargetValue(new BigDecimal("10.00"));
        goalReq.setTargetUnit("lb");
        goalReq.setDurationWeeks(10);
        goalReq.setStartDate(LocalDate.now().minusWeeks(1).format(FMT));
        GoalResponse goal = fitnessService.createGoal(testUser.getId(), goalReq);

        CheckinRequest checkinReq = new CheckinRequest();
        checkinReq.setCurrentValue(new BigDecimal("178.00"));
        checkinReq.setNotes("Feeling good");
        CheckinResponse checkinResp = fitnessService.performCheckin(
                testUser.getId(), goal.getId(), checkinReq);
        assertNotNull(checkinResp);
        assertEquals(new BigDecimal("178.00"), checkinResp.getCurrentValue());
    }

    @Test
    void testGoalStateTransitions() {
        GoalRequest req = new GoalRequest();
        req.setGoalType("ENDURANCE");
        req.setTargetValue(new BigDecimal("30.00"));
        req.setTargetUnit("minutes");
        req.setDurationWeeks(8);
        req.setStartDate(LocalDate.now().format(FMT));
        GoalResponse goal = fitnessService.createGoal(testUser.getId(), req);

        // ACTIVE → PAUSED
        fitnessService.pauseGoal(testUser.getId(), goal.getId());
        FitnessGoal paused = goalRepository.findById(goal.getId()).orElseThrow();
        assertEquals(FitnessGoal.GoalStatus.PAUSED, paused.getStatus());

        // PAUSED → ACTIVE
        fitnessService.resumeGoal(testUser.getId(), goal.getId());
        FitnessGoal resumed = goalRepository.findById(goal.getId()).orElseThrow();
        assertEquals(FitnessGoal.GoalStatus.ACTIVE, resumed.getStatus());

        // ACTIVE → CANCELLED
        fitnessService.cancelGoal(testUser.getId(), goal.getId());
        FitnessGoal cancelled = goalRepository.findById(goal.getId()).orElseThrow();
        assertEquals(FitnessGoal.GoalStatus.CANCELLED, cancelled.getStatus());
    }

    @Test
    void testObjectLevelAuth() {
        GoalRequest req = new GoalRequest();
        req.setGoalType("FLEXIBILITY");
        req.setTargetValue(new BigDecimal("5.00"));
        req.setTargetUnit("inches");
        req.setDurationWeeks(8);
        req.setStartDate(LocalDate.now().format(FMT));
        GoalResponse goal = fitnessService.createGoal(testUser.getId(), req);

        // Create another user
        Role role = roleRepository.findByName(Role.RoleName.REGULAR_USER).orElseThrow();
        User otherUser = new User();
        otherUser.setUsername("other_" + System.nanoTime());
        otherUser.setPasswordHash(passwordEncoder.encode("Test1234!"));
        otherUser.setRole(role);
        otherUser.setStatus(User.UserStatus.ACTIVE);
        otherUser = userRepository.save(otherUser);
        setSecurityContext(otherUser);

        Long otherId = otherUser.getId();
        Long goalId = goal.getId();
        assertThrows(AppException.class,
                () -> fitnessService.getGoalDetail(otherId, goalId));
    }
}

