import com.campusfit.study.dto.*;
import com.campusfit.study.entity.StudyPlan;
import com.campusfit.study.repository.StudyPlanRepository;
import com.campusfit.study.service.StudyService;
import com.campusfit.users.entity.User;
import com.campusfit.users.repository.UserRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

@SpringBootTest
@ActiveProfiles("test")
@Transactional
class StudyServiceTest {

    @Autowired private StudyService studyService;
    @Autowired private UserRepository userRepository;
    @Autowired private RoleRepository roleRepository;
    @Autowired private StudyPlanRepository planRepository;
    @Autowired private BCryptPasswordEncoder passwordEncoder;

    private User testUser;
    private static final DateTimeFormatter FMT = DateTimeFormatter.ofPattern("MM/dd/yyyy");

    @BeforeEach
    void setUp() {
        if (roleRepository.findByName(Role.RoleName.REGULAR_USER).isEmpty()) {
            roleRepository.save(new Role(Role.RoleName.REGULAR_USER));
            roleRepository.save(new Role(Role.RoleName.WAREHOUSE_STAFF));
            roleRepository.save(new Role(Role.RoleName.ADMINISTRATOR));
        }
        Role role = roleRepository.findByName(Role.RoleName.REGULAR_USER).orElseThrow();
        testUser = new User();
        testUser.setUsername("studyuser_" + System.nanoTime());
        testUser.setPasswordHash(passwordEncoder.encode("Test1234!"));
        testUser.setRole(role);
        testUser.setStatus(User.UserStatus.ACTIVE);
        testUser = userRepository.save(testUser);
        SecurityContextHolder.getContext().setAuthentication(
                new UsernamePasswordAuthenticationToken(testUser, null,
                        List.of(new SimpleGrantedAuthority("REGULAR_USER"))));
    }

    private StudyPlanRequest makePlanRequest() {
        StudyPlanRequest req = new StudyPlanRequest();
        req.setPlanName("Test Plan");
        req.setPlanType("STUDY");
        req.setDailyTargetMinutes(60);
        req.setStartDate(LocalDate.now().format(FMT));
        req.setEndDate(LocalDate.now().plusWeeks(8).format(FMT));
        return req;
    }

    @Test
    void testCreatePlan() {
        StudyPlanResponse resp = studyService.createPlan(testUser.getId(), makePlanRequest());
        assertNotNull(resp);
        assertEquals("Test Plan", resp.getPlanName());
        assertEquals(0, resp.getCurrentStreak());
    }

    @Test
    void testRecordCompletionUpdatesStreak() {
        StudyPlanResponse plan = studyService.createPlan(testUser.getId(), makePlanRequest());

        // Day 1
        CompletionRequest req1 = new CompletionRequest();
        req1.setCompletionDate(LocalDate.now().minusDays(1).format(FMT));
        req1.setMinutesSpent(45);
        req1.setTopicsCovered("Chapter 1");
        studyService.recordCompletion(testUser.getId(), plan.getId(), req1);

        // Day 2 (consecutive)
        CompletionRequest req2 = new CompletionRequest();
        req2.setCompletionDate(LocalDate.now().format(FMT));
        req2.setMinutesSpent(60);
        req2.setTopicsCovered("Chapter 2");
        CompletionResponse resp = studyService.recordCompletion(testUser.getId(), plan.getId(), req2);
        assertTrue(resp.getCurrentStreak() >= 2);
    }

    @Test
    void testStreakResetsOnGap() {
        StudyPlanResponse plan = studyService.createPlan(testUser.getId(), makePlanRequest());

        // Day 1
        CompletionRequest req1 = new CompletionRequest();
        req1.setCompletionDate(LocalDate.now().minusDays(3).format(FMT));
        req1.setMinutesSpent(30);
        studyService.recordCompletion(testUser.getId(), plan.getId(), req1);

        // Skip day 2, record day 3 (gap)
        CompletionRequest req3 = new CompletionRequest();
        req3.setCompletionDate(LocalDate.now().minusDays(1).format(FMT));
        req3.setMinutesSpent(30);
        CompletionResponse resp = studyService.recordCompletion(testUser.getId(), plan.getId(), req3);
        assertEquals(1, resp.getCurrentStreak());
    }

    @Test
    void testDuplicateCompletionBlocked() {
        StudyPlanResponse plan = studyService.createPlan(testUser.getId(), makePlanRequest());
        String today = LocalDate.now().format(FMT);

        CompletionRequest req = new CompletionRequest();
        req.setCompletionDate(today);
        req.setMinutesSpent(30);
        studyService.recordCompletion(testUser.getId(), plan.getId(), req);

        CompletionRequest req2 = new CompletionRequest();
        req2.setCompletionDate(today);
        req2.setMinutesSpent(60);
        assertThrows(AppException.class,
                () -> studyService.recordCompletion(testUser.getId(), plan.getId(), req2));
    }

    @Test
    void testAddForgettingPoint() {
        StudyPlanResponse plan = studyService.createPlan(testUser.getId(), makePlanRequest());
        ForgettingPointRequest fpReq = new ForgettingPointRequest();
        fpReq.setTopic("Quadratic Formula");
        fpReq.setDescription("Keep mixing up the signs");
        fpReq.setConfidenceLevel(2);
        ForgettingPointResponse fpResp = studyService.addForgettingPoint(
                testUser.getId(), plan.getId(), fpReq);
        assertNotNull(fpResp);
        assertEquals("Quadratic Formula", fpResp.getTopic());
        assertEquals(2, fpResp.getConfidenceLevel());
        assertEquals(0, fpResp.getReviewCount());
    }

    @Test
    void testLongestStreakNeverDecreases() {
        StudyPlanResponse plan = studyService.createPlan(testUser.getId(), makePlanRequest());

        // Build streak of 3
        for (int i = 3; i >= 1; i--) {
            CompletionRequest req = new CompletionRequest();
            req.setCompletionDate(LocalDate.now().minusDays(i).format(FMT));
            req.setMinutesSpent(30);
            studyService.recordCompletion(testUser.getId(), plan.getId(), req);
        }
        StudyPlan updated = planRepository.findById(plan.getId()).orElseThrow();
        int longestAfterFirst = updated.getLongestStreak();
        assertTrue(longestAfterFirst >= 3);

        // Break and rebuild smaller streak
        CompletionRequest newReq = new CompletionRequest();
        newReq.setCompletionDate(LocalDate.now().plusDays(2).format(FMT));
        newReq.setMinutesSpent(30);
        // This creates a gap, so streak resets
        studyService.recordCompletion(testUser.getId(), plan.getId(), newReq);
        StudyPlan afterBreak = planRepository.findById(plan.getId()).orElseThrow();
        assertTrue(afterBreak.getLongestStreak() >= longestAfterFirst);
    }
}

