package com.campusfit.inventory;

import com.campusfit.auth.entity.Role;
import com.campusfit.auth.repository.RoleRepository;
import com.campusfit.common.exception.AppException;
import com.campusfit.inventory.dto.*;
import com.campusfit.inventory.entity.InboundReceipt;
import com.campusfit.inventory.entity.Product;
import com.campusfit.inventory.entity.WarehouseLocation;
import com.campusfit.inventory.repository.*;
import com.campusfit.inventory.service.ReceivingService;
import com.campusfit.users.entity.User;
import com.campusfit.users.repository.UserRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

@SpringBootTest
@ActiveProfiles("test")
@Transactional
class ReceivingServiceTest {

    @Autowired private ReceivingService receivingService;
    @Autowired private UserRepository userRepository;
    @Autowired private RoleRepository roleRepository;
    @Autowired private InboundReceiptRepository receiptRepository;
    @Autowired private InboundReceiptEventRepository eventRepository;
    @Autowired private ProductRepository productRepository;
    @Autowired private WarehouseLocationRepository locationRepository;
    @Autowired private BCryptPasswordEncoder passwordEncoder;

    private User staffUser;
    private Product product;
    private WarehouseLocation location;

    @BeforeEach
    void setUp() {
        if (roleRepository.findByName(Role.RoleName.WAREHOUSE_STAFF).isEmpty()) {
            roleRepository.save(new Role(Role.RoleName.REGULAR_USER));
            roleRepository.save(new Role(Role.RoleName.WAREHOUSE_STAFF));
            roleRepository.save(new Role(Role.RoleName.ADMINISTRATOR));
        }
        Role role = roleRepository.findByName(Role.RoleName.WAREHOUSE_STAFF).orElseThrow();
        staffUser = new User();
        staffUser.setUsername("staff_" + System.nanoTime());
        staffUser.setPasswordHash(passwordEncoder.encode("Test1234!"));
        staffUser.setRole(role);
        staffUser.setStatus(User.UserStatus.ACTIVE);
        staffUser = userRepository.save(staffUser);
        SecurityContextHolder.getContext().setAuthentication(
                new UsernamePasswordAuthenticationToken(staffUser, null,
                        List.of(new SimpleGrantedAuthority("WAREHOUSE_STAFF"))));

        product = new Product();
        product.setSku("SKU-" + System.nanoTime());
        product.setName("Test Product");
        product.setCategory("General");
        product.setUnitOfMeasure("EA");
        product.setStatus("ACTIVE");
        product = productRepository.save(product);

        location = new WarehouseLocation();
        location.setCode("LOC-" + System.nanoTime());
        location.setName("Shelf A1");
        location.setZone("A");
        location.setAisle("1");
        location.setCapacity(100);
        location.setCurrentOccupancy(0);
        location.setStatus("ACTIVE");
        location = locationRepository.save(location);
    }

    private ReceiptCreateRequest makeReceiptRequest() {
        ReceiptCreateRequest req = new ReceiptCreateRequest();
        req.setReferenceNumber("RCV-" + System.nanoTime());
        req.setReceiptType("PURCHASE");
        LineRequest line = new LineRequest();
        line.setProductId(product.getId());
        line.setExpectedQuantity(100);
        req.setLines(List.of(line));
        return req;
    }

    @Test
    void testCreateReceipt() {
        ReceiptResponse resp = receivingService.createReceipt(makeReceiptRequest());
        assertNotNull(resp);
        assertEquals("DRAFT", resp.getStatus());
        assertTrue(eventRepository.findByReceiptIdOrderByCreatedAtAsc(resp.getId()).size() >= 1);
    }

    @Test
    void testStateTransitions() {
        ReceiptResponse receipt = receivingService.createReceipt(makeReceiptRequest());
        Long id = receipt.getId();

        // DRAFT → RECEIVING
        receivingService.startReceiving(id);
        assertEquals("RECEIVING", receiptRepository.findById(id).orElseThrow().getStatus().name());

        // Record quantities (exact match, no discrepancy)
        ReceiveRequest.ReceiveLine rl = new ReceiveRequest.ReceiveLine();
        rl.setLineId(receipt.getLines().get(0).getId());
        rl.setReceivedQuantity(100);
        ReceiveRequest rr = new ReceiveRequest();
        rr.setLines(List.of(rl));
        receivingService.recordQuantities(id, rr);

        // RECEIVING → INSPECTION
        InspectionRequest ir = new InspectionRequest();
        ir.setLineId(receipt.getLines().get(0).getId());
        ir.setInspectionResult("PASS");
        receivingService.performInspection(id, List.of(ir));

        InboundReceipt inspected = receiptRepository.findById(id).orElseThrow();
        assertEquals(InboundReceipt.ReceiptStatus.INSPECTION, inspected.getStatus());
    }

    @Test
    void testInvalidTransition() {
        ReceiptResponse receipt = receivingService.createReceipt(makeReceiptRequest());
        // Try DRAFT → COMPLETED directly (should fail)
        assertThrows(AppException.class,
                () -> receivingService.completeReceipt(receipt.getId()));
    }

    @Test
    void testVarianceCalculation() {
        ReceiptResponse receipt = receivingService.createReceipt(makeReceiptRequest());
        receivingService.startReceiving(receipt.getId());

        // Receive only 94 out of 100 (6% variance, >2% threshold AND >5 units)
        ReceiveRequest.ReceiveLine rl = new ReceiveRequest.ReceiveLine();
        rl.setLineId(receipt.getLines().get(0).getId());
        rl.setReceivedQuantity(94);
        ReceiveRequest rr = new ReceiveRequest();
        rr.setLines(List.of(rl));
        receivingService.recordQuantities(receipt.getId(), rr);

        InboundReceipt updated = receiptRepository.findById(receipt.getId()).orElseThrow();
        assertTrue(updated.isRequiresSupervisorReview(),
                "Should require supervisor review for >2% variance");
    }

    @Test
    void testRejectReceipt() {
        ReceiptResponse receipt = receivingService.createReceipt(makeReceiptRequest());
        receivingService.rejectReceipt(receipt.getId(), "Damaged goods");

        InboundReceipt rejected = receiptRepository.findById(receipt.getId()).orElseThrow();
        assertEquals(InboundReceipt.ReceiptStatus.REJECTED, rejected.getStatus());
    }

    @Test
    void testAllTransitionsRecordEvents() {
        ReceiptResponse receipt = receivingService.createReceipt(makeReceiptRequest());
        Long id = receipt.getId();
