package com.campusfit.security;

import com.campusfit.config.AppConfig;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

import java.io.File;
import java.io.FileOutputStream;
import java.nio.file.Path;

import static org.junit.jupiter.api.Assertions.*;

class EncryptionServiceTest {

    private EncryptionService encryptionService;

    @TempDir
    Path tempDir;

    @BeforeEach
    void setUp() throws Exception {
        // Create a test key file
        File keyFile = tempDir.resolve("test-key.key").toFile();
        try (FileOutputStream fos = new FileOutputStream(keyFile)) {
            byte[] key = new byte[32];
            for (int i = 0; i < 32; i++) key[i] = (byte) (i + 65);
            fos.write(key);
        }

        AppConfig config = new AppConfig();
        config.setEncryption(new AppConfig.EncryptionConfig());
        config.getEncryption().setActiveKeyId("test-key");
        config.getEncryption().setKeyDir(tempDir.toString());
        config.getEncryption().setAlgorithm("AES/GCM/NoPadding");

        encryptionService = new EncryptionService(config);
        encryptionService.init();
    }

    @Test
    void testEncryptDecryptRoundtrip() {
        String plaintext = "Hello, CampusFit!";
        String encrypted = encryptionService.encrypt(plaintext);
        String decrypted = encryptionService.decrypt(encrypted);
        assertEquals(plaintext, decrypted);
    }

    @Test
    void testDifferentPlaintextsProduceDifferentCiphertexts() {
        String encrypted1 = encryptionService.encrypt("same text");
        String encrypted2 = encryptionService.encrypt("same text");
        assertNotEquals(encrypted1, encrypted2, "Different IVs should produce different ciphertexts");
    }

    @Test
    void testCiphertextContainsKeyId() {
        String encrypted = encryptionService.encrypt("test");
        assertTrue(encrypted.startsWith("test-key:"),
                "Ciphertext should start with key ID prefix");
    }

    @Test
    void testDecryptWithTamperedCiphertextFails() {
        String encrypted = encryptionService.encrypt("original");
        String tampered = encrypted.substring(0, encrypted.length() - 4) + "XXXX";
        assertThrows(Exception.class, () -> encryptionService.decrypt(tampered));
    }

    @Test
    void testReEncrypt() {
        String original = "sensitive data";
        String encrypted = encryptionService.encrypt(original);
        String reEncrypted = encryptionService.reEncrypt(encrypted);

        assertNotEquals(encrypted, reEncrypted);
        assertEquals(original, encryptionService.decrypt(reEncrypted));
    }
}

