package com.campusfit.integration;

import com.campusfit.auth.dto.AuthResponse;
import com.campusfit.auth.dto.RegisterRequest;
import com.campusfit.auth.entity.Role;
import com.campusfit.auth.repository.RoleRepository;
import com.campusfit.auth.service.AuthService;
import com.campusfit.fitness.dto.AssessmentRequest;
import com.campusfit.fitness.dto.AssessmentResponse;
import com.campusfit.fitness.dto.GoalRequest;
import com.campusfit.fitness.dto.GoalResponse;
import com.campusfit.fitness.service.FitnessService;
import com.campusfit.study.dto.CompletionRequest;
import com.campusfit.study.dto.StudyPlanRequest;
import com.campusfit.study.dto.StudyPlanResponse;
import com.campusfit.study.service.StudyService;
import com.campusfit.users.entity.User;
import com.campusfit.users.repository.UserRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

@SpringBootTest
@ActiveProfiles("test")
@Transactional
class EndToEndFlowTest {

    @Autowired private AuthService authService;
    @Autowired private FitnessService fitnessService;
    @Autowired private StudyService studyService;
    @Autowired private UserRepository userRepository;
    @Autowired private RoleRepository roleRepository;

    private static final DateTimeFormatter FMT = DateTimeFormatter.ofPattern("MM/dd/yyyy");

    @BeforeEach
    void setUp() {
        if (roleRepository.findByName(Role.RoleName.REGULAR_USER).isEmpty()) {
            roleRepository.save(new Role(Role.RoleName.REGULAR_USER));
            roleRepository.save(new Role(Role.RoleName.WAREHOUSE_STAFF));
            roleRepository.save(new Role(Role.RoleName.ADMINISTRATOR));
        }
    }

    private AuthResponse registerUser(String username) {
        RegisterRequest req = new RegisterRequest();
        req.setUsername(username);
        req.setPassword("Test1234!");
        req.setEmail(username + "@test.com");
        req.setFullName("Test User");
        AuthResponse resp = authService.register(req);
        User user = userRepository.findByUsername(username).orElseThrow();
        SecurityContextHolder.getContext().setAuthentication(
                new UsernamePasswordAuthenticationToken(user, null,
                        List.of(new SimpleGrantedAuthority(user.getRole().getName().name()))));
        return resp;
    }

    @Test
    void testFullFitnessFlow() {
        // 1. Register
        AuthResponse auth = registerUser("fit_e2e_" + System.nanoTime());
        User user = userRepository.findByUsername(auth.getUsername()).orElseThrow();
        Long userId = user.getId();

        // 2. Create assessment
        AssessmentRequest aReq = new AssessmentRequest();
        aReq.setHeightFt(5);
        aReq.setHeightIn(10);
        aReq.setWeightLb(new BigDecimal("185.00"));
        aReq.setAssessmentDate(LocalDate.now().format(FMT));
        AssessmentResponse assessment = fitnessService.createAssessment(userId, aReq);
        assertNotNull(assessment);

        // 3. Create goal
        GoalRequest gReq = new GoalRequest();
        gReq.setGoalType("WEIGHT_LOSS");
        gReq.setTargetValue(new BigDecimal("12.00"));
        gReq.setTargetUnit("lb");
        gReq.setDurationWeeks(12);
        gReq.setStartDate(LocalDate.now().format(FMT));
        GoalResponse goal = fitnessService.createGoal(userId, gReq);
        assertNotNull(goal);
        assertNotNull(goal.getPhases());
        assertTrue(goal.getPhases().size() > 0);

        // 4. View dashboard
        var dashboard = fitnessService.getDashboard(userId);
        assertNotNull(dashboard);
    }

    @Test
    void testFullStudyFlow() {
        // 1. Register
        AuthResponse auth = registerUser("study_e2e_" + System.nanoTime());
        User user = userRepository.findByUsername(auth.getUsername()).orElseThrow();
        Long userId = user.getId();

        // 2. Create plan
        StudyPlanRequest pReq = new StudyPlanRequest();
        pReq.setPlanName("Calculus Review");
        pReq.setPlanType("REVIEW");
        pReq.setDailyTargetMinutes(45);
        pReq.setStartDate(LocalDate.now().format(FMT));
        pReq.setEndDate(LocalDate.now().plusWeeks(4).format(FMT));
        StudyPlanResponse plan = studyService.createPlan(userId, pReq);
        assertNotNull(plan);

        // 3. Record completion
        CompletionRequest cReq = new CompletionRequest();
        cReq.setCompletionDate(LocalDate.now().format(FMT));
        cReq.setMinutesSpent(50);
        cReq.setTopicsCovered("Derivatives");
        var completion = studyService.recordCompletion(userId, plan.getId(), cReq);
        assertNotNull(completion);
        assertTrue(completion.getCurrentStreak() >= 1);
    }

    @Test
    void testCrossUserAccessBlocked() {
        // User A creates a goal
        AuthResponse authA = registerUser("userA_" + System.nanoTime());
        User userA = userRepository.findByUsername(authA.getUsername()).orElseThrow();

        GoalRequest gReq = new GoalRequest();
        gReq.setGoalType("ENDURANCE");
        gReq.setTargetValue(new BigDecimal("10.00"));
        gReq.setTargetUnit("km");
        gReq.setDurationWeeks(8);
        gReq.setStartDate(LocalDate.now().format(FMT));
        GoalResponse goal = fitnessService.createGoal(userA.getId(), gReq);

        // User B tries to access
        AuthResponse authB = registerUser("userB_" + System.nanoTime());
        User userB = userRepository.findByUsername(authB.getUsername()).orElseThrow();
        SecurityContextHolder.getContext().setAuthentication(
                new UsernamePasswordAuthenticationToken(userB, null,
                        List.of(new SimpleGrantedAuthority("REGULAR_USER"))));

        assertThrows(Exception.class,
                () -> fitnessService.getGoalDetail(userB.getId(), goal.getId()));
    }
}

